#!/bin/bash
# Custom pre-commit hook installer that filters out "Skipped" messages

set -euo pipefail

# First, install the standard pre-commit hooks
pre-commit install

# Now, replace the standard hook with a filtered wrapper
cat > .git/hooks/pre-commit << 'EOF'
#!/usr/bin/env bash
# File generated by pre-commit: https://pre-commit.com
# Custom wrapper that filters pre-commit output

# start templated
INSTALL_PYTHON=/usr/bin/python3
ARGS=(hook-impl --config=.pre-commit-config.yaml --hook-type=pre-commit)
# end templated

HERE="$(cd "$(dirname "$0")" && pwd)"
ARGS+=(--hook-dir "$HERE" -- "$@")

# Run pre-commit and filter skipped messages
if [ -x "$INSTALL_PYTHON" ]; then
    "$INSTALL_PYTHON" -mpre_commit "${ARGS[@]}" 2>&1 | grep -v "(no files to check)Skipped" || true
    exit ${PIPESTATUS[0]}
elif command -v pre-commit > /dev/null; then
    pre-commit "${ARGS[@]}" 2>&1 | grep -v "(no files to check)Skipped" || true
    exit ${PIPESTATUS[0]}
else
    echo '`pre-commit` not found.  Did you forget to activate your virtualenv?' 1>&2
    exit 1
fi
EOF

# Make the hook executable
chmod +x .git/hooks/pre-commit

echo "Pre-commit hook installed with output filtering"
echo "Skipped hooks will not be displayed in output"
